﻿"use client";

import { motion, useScroll, useTransform, useSpring } from "motion/react";
import Link from "next/link";
import { ArrowUpRight } from "lucide-react";
import { collegesData } from "@/data/colleges";
import ParticleBackground from "@/components/ParticleBackground";

import { useRef } from "react";
const calmEase = [0.25, 0.1, 0.25, 1] as const;

const heroReveal = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0, transition: { duration: 1.2, ease: calmEase } }
};

const fadeSlideUp = {
  hidden: { opacity: 0, y: 30 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 1.0, ease: calmEase }
  }
};

const staggerChildren = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { staggerChildren: 0.15, delayChildren: 0.2 }
  }
};

export default function Home() {
  const containerRef = useRef<HTMLDivElement>(null);

  // Curtain Engine
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end end"]
  });

  const smoothProgress = useSpring(scrollYProgress, { stiffness: 100, damping: 20 });

  // Hero curtain lifts from 0% to -100% between 30% and 100% scroll of the 250vh container.
  const curtainY = useTransform(smoothProgress, [0.3, 1], ["0%", "-100%"]);

  // Text Animation: Scale down, move to top-left, and fold slightly on X-axis between 0% and 30%
  const textScale = useTransform(smoothProgress, [0, 0.3], [1, 0.15]);
  const textX = useTransform(smoothProgress, [0, 0.3], ["0vw", "-42vw"]);
  const textY = useTransform(smoothProgress, [0, 0.3], ["0vh", "-45vh"]);
  const textRotateX = useTransform(smoothProgress, [0, 0.2], [0, 60]);
  const textRotateY = useTransform(smoothProgress, [0.2, 0.3], [0, -10]);
  const textOpacity = useTransform(smoothProgress, [0.25, 0.3], [1, 0]); // Fades out as it reaches the real navbar

  // The next section (Stage) subtly rises and fades in simultaneously.
  const stageY = useTransform(smoothProgress, [0.3, 1], ["10%", "0%"]);
  const stageOpacity = useTransform(smoothProgress, [0.3, 0.8], [0, 1]);

  return (
    <div className="w-full bg-[var(--color-bg-page)] overflow-clip">

      {/* SECTION 1 & 2 - HERO CURTAIN ENGINE */}
      <section ref={containerRef} className="relative h-[250vh] w-full bg-[#0A0A0F]">

        {/* THE PINNED VIEWPORT */}
        <div className="sticky top-0 h-screen w-full overflow-hidden bg-[#0A0A0F]">

          {/* THE STAGE (Next Section) - Fixed at z-10 directly underneath */}
          <div className="absolute inset-0 z-10 flex flex-col items-center justify-center bg-[#0A0A0F] px-6">
            <motion.div
              style={{ y: stageY, opacity: stageOpacity }}
              className="flex flex-col items-center text-center space-y-8 max-w-5xl mx-auto w-full"
            >
              <p className="text-2xl md:text-3xl lg:text-4xl font-[family-name:var(--font-heading)] text-[#F1F1F1] leading-[1.5] tracking-widest uppercase">
                "Precision in planning <br className="hidden md:block" /> defines the trajectory of success."
              </p>
              <div className="h-16 w-px bg-gradient-to-b from-[#B89C4A]/50 to-transparent my-10 mx-auto" />
              <p className="text-[#8A8A8A] max-w-2xl text-base md:text-lg font-light leading-relaxed mx-auto">
                We bypass the superfluous, architecting concrete educational pathways. Our methodology relies on objective aptitude mapping to place talent within optimal academic infrastructures.
              </p>
            </motion.div>
          </div>

          {/* THE CURTAIN (Hero) background that lifts */}
          <motion.div
            style={{ y: curtainY }}
            className="absolute inset-0 z-20 bg-[#0A0A0F] shadow-[0_20px_50px_rgba(0,0,0,0.5)] overflow-hidden"
          >
            {/* 3D PARTICLE Parallax Animation */}
            <ParticleBackground />

            <div className="absolute inset-0 z-10 flex flex-col items-center justify-center pointer-events-none">
              <h2 className="text-xs sm:text-sm md:text-base text-[#8A8A8A] font-light tracking-[0.4em] uppercase mt-[15vh] mb-10">
                Elite Admission Architects
              </h2>
              <div className="h-[1px] w-12 bg-[#B89C4A] opacity-40 mx-auto" />
            </div>

            <div className="absolute bottom-12 right-12 z-10 hidden md:block">
              <p className="text-[#F1F1F1] text-[18px] md:text-[24px] font-medium tracking-[0.1em] uppercase">
                SCROLL TO EXPLORE
              </p>
            </div>

            {/* Minimalist crosshairs / UI accents from Lusion reference */}
            <div className="absolute left-[5%] top-[50%] hidden md:block text-[#F1F1F1]/30 text-xl font-light pointer-events-none">+</div>
            <div className="absolute right-[5%] top-[50%] hidden md:block text-[#F1F1F1]/30 text-xl font-light pointer-events-none">+</div>
            <div className="absolute left-[25%] top-[50%] hidden md:block text-[#F1F1F1]/30 text-xl font-light pointer-events-none">+</div>
            <div className="absolute right-[25%] top-[50%] hidden md:block text-[#F1F1F1]/30 text-xl font-light pointer-events-none">+</div>
          </motion.div>

          {/* THE TRANSFORMING TEXT - Positioned absolute in the pinned viewport, higher z-index so it doesn't clip */}
          <motion.div
            style={{
              x: textX,
              y: textY,
              scale: textScale,
              rotateX: textRotateX,
              rotateY: textRotateY,
              opacity: textOpacity
            }}
            className="absolute inset-0 z-30 flex items-center justify-center pointer-events-none origin-center"
          // Adding origin-center ensures scale and transform work predictably
          >
            <h1
              className="text-6xl sm:text-8xl md:text-9xl lg:text-[14rem] font-bold text-[#F1F1F1] tracking-[-0.02em] leading-none whitespace-nowrap drop-shadow-[0_0_20px_rgba(255,255,255,0.1)]"
              style={{ fontFamily: "'Inter', 'Helvetica Now Display', 'Helvetica Neue', Helvetica, Arial, sans-serif" }}
            >
              WISDOM NEXUS
            </h1>
          </motion.div>

        </div>
      </section>

      {/* SECTION 3 - PATHWAY PANELS (SERVICES) */}
      <section className="py-24 max-w-7xl mx-auto px-4 md:px-8 bg-[#111118]/50">
        <motion.div
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, amount: 0.2 }}
          variants={staggerChildren}
          className="grid grid-cols-1 md:grid-cols-2 gap-6 md:gap-8"
        >
          <div className="col-span-1 md:col-span-2 flex flex-col items-center text-center mb-16">
            <motion.h3 variants={fadeSlideUp} className="text-3xl md:text-4xl font-[family-name:var(--font-heading)] text-[#F1F1F1] tracking-wide mb-4">
              Strategic Pathways
            </motion.h3>
            <motion.div variants={fadeSlideUp} className="h-px w-12 bg-[#B89C4A] opacity-50" />
          </div>

          {[
            { title: "Academic Institutions", desc: "Curated profiles of premier autonomous and university-affiliated colleges.", link: "/colleges" },
            { title: "Global Education Strategy", desc: "Consultative approach to international university placements and compliance.", link: "/study-abroad" },
            { title: "Cognitive & Aptitude Mapping", desc: "DMIT and psychological assessments mapping intrinsic capability to career choices.", link: "/dmit" },
            { title: "Career Structuring", desc: "Long-term architectural planning for postgraduate and doctoral trajectories.", link: "/contact" }
          ].map((panel, i) => (
            <motion.div key={i} variants={fadeSlideUp}>
              <Link href={panel.link} className="block w-full h-full p-10 architectural-panel group relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-[2px] bg-gradient-to-r from-transparent via-[#B89C4A] to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-700" />
                <h4 className="text-2xl font-[family-name:var(--font-heading)] text-[#F1F1F1] mb-4 tracking-wide group-hover:text-[#B89C4A] transition-colors duration-500">{panel.title}</h4>
                <p className="text-[#6E6E6E] text-sm md:text-base leading-relaxed max-w-sm mb-12 group-hover:text-[#8A8A8A] transition-colors duration-500 font-light">{panel.desc}</p>
                <div className="flex justify-between items-end">
                  <span className="text-xs uppercase tracking-[0.2em] text-[#B89C4A]">Explore</span>
                  <ArrowUpRight size={24} className="text-[#6E6E6E] group-hover:text-[#B89C4A] transition-colors duration-500" />
                </div>
              </Link>
            </motion.div>
          ))}
        </motion.div>
      </section>

      {/* TOP COLLEGES (MINIMALIST) */}
      <section className="py-32 max-w-7xl mx-auto px-4 md:px-8">
        <motion.div
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, amount: 0.2 }}
          variants={staggerChildren}
          className="flex flex-col mb-16"
        >
          <motion.h3 variants={fadeSlideUp} className="text-3xl md:text-4xl font-[family-name:var(--font-heading)] text-[#F1F1F1] tracking-wide mb-6">
            Institutional Portfolio
          </motion.h3>
          <div className="flex justify-between items-end border-b border-[#B89C4A]/20 pb-4">
            <motion.p variants={fadeSlideUp} className="text-[#8A8A8A] max-w-lg text-sm leading-relaxed font-light">
              Selecting infrastructure that demands excellence. Our portfolio consists only of institutions that meet stringent academic and placement criteria.
            </motion.p>
            <motion.div variants={fadeSlideUp} className="hidden md:block">
              <Link href="/colleges" className="text-xs uppercase tracking-widest text-[#B89C4A] hover:text-[#F1F1F1] transition-colors pb-1 border-b border-transparent hover:border-[#F1F1F1]">
                View Directory
              </Link>
            </motion.div>
          </div>
        </motion.div>

        <motion.div
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, amount: 0.1 }}
          variants={staggerChildren}
          className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-6"
        >
          {collegesData.slice(0, 4).map((college, i) => (
            <motion.div key={i} variants={fadeSlideUp} className="architectural-panel p-6 flex flex-col">
              <div className="w-12 h-12 mb-6 border border-[#B89C4A]/30 flex justify-center items-center text-xl text-[#B89C4A] bg-[#0A0A0F]">
                {college.logo}
              </div>
              <h4 className="text-lg font-[family-name:var(--font-heading)] text-[#F1F1F1] mb-2 leading-snug">{college.name}</h4>
              <p className="text-[#6E6E6E] text-xs uppercase tracking-wider mb-8">{college.location}</p>
              <div className="mt-auto pt-4 border-t border-[#B89C4A]/10">
                <Link href={`/colleges`} className="text-xs uppercase tracking-widest text-[#8A8A8A] hover:text-[#B89C4A] transition-colors flex items-center gap-2">
                  Access Details <ArrowUpRight size={14} />
                </Link>
              </div>
            </motion.div>
          ))}
        </motion.div>
      </section>

      {/* REFINED TESTIMONIALS */}
      <section className="py-24 bg-[#111118]/80 border-t border-b border-[#B89C4A]/10">
        <div className="max-w-7xl mx-auto px-4 md:px-8">
          <motion.div
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true, amount: 0.2 }}
            variants={staggerChildren}
            className="flex justify-between items-center mb-16"
          >
            <motion.h3 variants={fadeSlideUp} className="text-2xl font-[family-name:var(--font-heading)] text-[#F1F1F1] tracking-wide">
              Client Trajectories
            </motion.h3>
            <motion.div variants={fadeSlideUp} className="hidden md:flex gap-1">
              <div className="w-2 h-2 bg-[#B89C4A]/50" />
              <div className="w-2 h-2 bg-[#B89C4A]" />
            </motion.div>
          </motion.div>

          <motion.div
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true, amount: 0.2 }}
            variants={staggerChildren}
            className="grid grid-cols-1 md:grid-cols-3 gap-8"
          >
            {[
              { name: "Rahul K.", role: "B.Tech Engineering", text: "The architectural approach to my counseling isolated the noise. I was presented with clear data, allowing a precise decision for an autonomous campus." },
              { name: "Priya Sharma", role: "Management Studies", text: "Confidence is exactly what Wisdom Nexus provided. Navigating management quotas was handled with absolute transparency and strategic insight." },
              { name: "Anita Desai", role: "Medical Admissions", text: "A highly structured process. They outlined exact requirements, timelines, and NMC compliances without the typical consultancy pressure." }
            ].map((review, i) => (
              <motion.div key={i} variants={fadeSlideUp} className="p-8 border-l border-[#B89C4A]/30">
                <p className="text-[#8A8A8A] text-sm md:text-base leading-relaxed mb-8 font-light italic">"{review.text}"</p>
                <div>
                  <h5 className="text-[#F1F1F1] text-sm font-medium tracking-wide uppercase">{review.name}</h5>
                  <p className="text-[#6E6E6E] text-xs tracking-wider uppercase mt-1">{review.role}</p>
                </div>
              </motion.div>
            ))}
          </motion.div>
        </div>
      </section>

      {/* MINIMAL CTA */}
      <section className="py-32 md:py-48 max-w-5xl mx-auto px-6 text-center">
        <motion.div
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, amount: 0.5 }}
          variants={staggerChildren}
          className="flex flex-col items-center"
        >
          <motion.h2 variants={fadeSlideUp} className="text-4xl md:text-5xl font-[family-name:var(--font-heading)] text-[#F1F1F1] mb-8 tracking-wide">
            Initiate Consultation
          </motion.h2>
          <motion.p variants={fadeSlideUp} className="text-[#8A8A8A] max-w-xl mx-auto mb-12 font-light leading-relaxed">
            Reserved exclusively for candidates seeking serious, structural advising for higher education.
          </motion.p>
          <motion.div variants={fadeSlideUp}>
            <Link href="/contact" className="btn-primary px-10 py-4 text-sm tracking-[0.2em] uppercase inline-flex items-center gap-4">
              Access Advisory <ArrowUpRight size={18} className="text-[#B89C4A]" />
            </Link>
          </motion.div>
        </motion.div>
      </section>
    </div>
  );
}

"use client";

import { motion, AnimatePresence } from "motion/react";
import { useState } from "react";
import { studyAbroadCountries } from "@/data/countries";
import {
    ChevronDown, MapPin, Landmark, Briefcase,
    CheckCircle, BookOpen, GraduationCap, ArrowRight, DollarSign,
    Clock, Award, Sparkles, Building2, Ticket, GraduationCap as GradIcon,
    Plane, ShieldCheck, Map
} from "lucide-react";
import Link from "next/link";
import Image from "next/image";
import { IconBrandWhatsapp } from "@tabler/icons-react";

export default function CountrySection() {
    const [expandedId, setExpandedId] = useState<string | null>(null);

    const toggleExpand = (id: string, e: React.MouseEvent<HTMLDivElement>) => {
        const isExpanding = expandedId !== id;
        setExpandedId(isExpanding ? id : null);
    };

    const primaryEase = [0.22, 1, 0.36, 1] as const;

    const contentStagger = {
        hidden: { opacity: 0 },
        visible: { opacity: 1, transition: { staggerChildren: 0.1, delayChildren: 0.2 } }
    };

    const subsectionReveal = {
        hidden: { opacity: 0, y: 16 },
        visible: { opacity: 1, y: 0, transition: { duration: 0.5, ease: primaryEase } }
    };

    const dividerReveal = {
        hidden: { scaleX: 0, opacity: 0 },
        visible: { scaleX: 1, opacity: 1, transition: { duration: 0.8, ease: primaryEase } }
    };

    const universityReaveal = {
        hidden: { opacity: 0, x: -16 },
        visible: { opacity: 1, x: 0, transition: { duration: 0.5, ease: primaryEase } }
    };

    const tagStagger = {
        hidden: { opacity: 0 },
        visible: { opacity: 1, transition: { staggerChildren: 0.06 } }
    };

    const tagReveal = {
        hidden: { opacity: 0, scale: 0.95 },
        visible: { opacity: 1, scale: 1, transition: { duration: 0.3, ease: primaryEase } }
    };

    return (
        <div className="w-full max-w-[1200px] mx-auto px-4 sm:px-6 lg:px-8 space-y-12 pb-20 relative z-30">
            {studyAbroadCountries.map((country) => (
                <div
                    key={country.id}
                    className={`w-full bg-[#0A0A0F] transition-all duration-500 architectural-panel ${expandedId === country.id
                        ? "border-[#B89C4A]/40"
                        : "cursor-pointer"
                        }`}
                >
                    {/* Collapsed/Header State */}
                    <div
                        onClick={(e) => toggleExpand(country.id, e)}
                        className={`w-full p-8 md:p-10 flex flex-col md:flex-row gap-8 items-start md:items-center justify-between transition-colors duration-300 ${expandedId === country.id ? "border-b border-[#B89C4A]/10 bg-[#111118]" : ""
                            }`}
                        style={{ cursor: expandedId === country.id ? "default" : "pointer" }}
                    >
                        {expandedId !== country.id && (
                            <motion.div
                                layoutId={`country-img-${country.id}`}
                                className="w-full md:w-48 h-48 md:h-32 bg-[#111118] shrink-0 overflow-hidden relative border border-[#B89C4A]/20"
                            >
                                <Image
                                    src={country.image}
                                    alt={`${country.name} landscape`}
                                    fill
                                    className="object-cover transition-transform duration-700 hover:scale-105 opacity-80"
                                    sizes="(max-width: 768px) 100vw, 192px"
                                    priority={country.id === 'canada' || country.id === 'uk'}
                                />
                                <div className="absolute inset-0 bg-[#0A0A0F]/20 mix-blend-overlay"></div>
                            </motion.div>
                        )}

                        {/* Title & Tagline */}
                        <div className="flex-1 w-full">
                            <div className="flex items-center gap-4 mb-2">
                                <span className="text-4xl opacity-80 grayscale-[30%]">{country.flag}</span>
                                <h3 className="text-3xl md:text-4xl font-[family-name:var(--font-heading)] text-[#F1F1F1] tracking-wide">{country.name}</h3>
                            </div>
                            <p className="text-sm md:text-base text-[#B89C4A] font-light tracking-widest uppercase mt-3">{country.tagline}</p>

                            {/* Summary Tags */}
                            <div className="flex flex-wrap items-center gap-x-8 gap-y-4 mt-8">
                                <span className="flex items-center gap-2 text-xs font-medium tracking-widest uppercase text-[#8A8A8A]">
                                    <DollarSign size={16} className="text-[#B89C4A]" /> {country.tuition}
                                </span>
                                <span className="flex items-center gap-2 text-xs font-medium tracking-widest uppercase text-[#8A8A8A]">
                                    <Briefcase size={16} className="text-[#B89C4A]" /> {country.work}
                                </span>
                                <span className="flex items-center gap-2 text-xs font-medium tracking-widest uppercase text-[#8A8A8A]">
                                    <Clock size={16} className="text-[#B89C4A]" /> {country.postStudy}
                                </span>
                                <span className="flex items-center gap-2 text-xs font-medium tracking-widest uppercase text-[#8A8A8A]">
                                    <Award size={16} className="text-[#B89C4A]" /> {country.prPathway}
                                </span>
                            </div>
                        </div>

                        {/* Expand Icon */}
                        <div className="mt-4 md:mt-2 shrink-0 md:self-center self-end">
                            <motion.div animate={{ rotate: expandedId === country.id ? 180 : 0 }} transition={{ duration: 0.5, ease: [0.32, 0.72, 0, 1] }}>
                                <ChevronDown size={32} className={`transition-colors duration-300 ${expandedId === country.id ? "text-[#B89C4A]" : "text-[#6E6E6E] hover:text-[#F1F1F1]"}`} />
                            </motion.div>
                        </div>
                    </div>

                    {/* Expanded Content State */}
                    <AnimatePresence>
                        {expandedId === country.id && (
                            <motion.div
                                initial={{ height: 0, opacity: 0 }}
                                animate={{ height: "auto", opacity: 1 }}
                                exit={{ height: 0, opacity: 0 }}
                                transition={{ duration: 0.6, ease: [0.32, 0.72, 0, 1] }}
                                className="overflow-hidden bg-[#0A0A0F]"
                            >
                                <motion.div variants={contentStagger} initial="hidden" animate="visible" exit="hidden" className="p-8 md:p-12 space-y-16">

                                    {/* 1 Hero Subsection */}
                                    <motion.div variants={subsectionReveal} className="flex flex-col md:flex-row gap-8 lg:gap-12 items-stretch relative z-10">
                                        <motion.div
                                            layoutId={`country-img-${country.id}`}
                                            className="w-full md:w-1/2 lg:w-5/12 h-64 md:h-auto min-h-[300px] bg-[#111118] shrink-0 overflow-hidden relative border border-[#B89C4A]/20"
                                        >
                                            <Image
                                                src={country.image}
                                                alt={`${country.name} landscape`}
                                                fill
                                                className="object-cover opacity-70"
                                                sizes="(max-width: 768px) 100vw, (max-width: 1024px) 50vw, 500px"
                                            />
                                            <div className="absolute inset-0 bg-gradient-to-t from-[#0A0A0F] via-transparent to-transparent opacity-80"></div>
                                        </motion.div>

                                        <div className="flex-1 w-full flex flex-col justify-center">
                                            <h2 className="text-3xl md:text-4xl font-[family-name:var(--font-heading)] text-[#F1F1F1] tracking-wide mb-6">
                                                Study in <span className="text-[#B89C4A]">{country.name}</span>
                                            </h2>
                                            <div className="w-16 h-px bg-[#B89C4A] mb-6 opacity-60"></div>
                                            <p className="text-sm md:text-base text-[#8A8A8A] leading-relaxed font-light">
                                                {country.name} offers Indian students exceptional strategic advantages.
                                                Explore world-leading academic programs, post-study work regulations, and admission requirements tailored for international success.
                                            </p>
                                        </div>
                                    </motion.div>

                                    {/* 2 & 5 Grid */}
                                    <motion.div variants={subsectionReveal} className="grid grid-cols-1 lg:grid-cols-2 gap-12 lg:gap-20 relative z-10">

                                        {/* Why Study */}
                                        <div className="relative z-10 p-8 border border-[#B89C4A]/20 bg-[#111118]">
                                            <h3 className="flex items-center gap-4 text-lg tracking-[0.2em] uppercase font-medium text-[#F1F1F1] mb-8">
                                                <Sparkles size={20} className="text-[#B89C4A]" /> Strategic Value
                                            </h3>
                                            <ul className="space-y-5">
                                                {country.whyStudy.map((point, idx) => (
                                                    <li key={idx} className="flex items-start gap-4">
                                                        <div className="mt-1.5 w-1.5 h-1.5 bg-[#B89C4A] shrink-0"></div>
                                                        <span className="text-[#8A8A8A] font-light text-sm leading-relaxed">{point}</span>
                                                    </li>
                                                ))}
                                            </ul>
                                        </div>

                                        {/* Tuition & Living */}
                                        <div className="relative z-10">
                                            <h3 className="flex items-center gap-4 text-lg tracking-[0.2em] uppercase font-medium text-[#F1F1F1] mb-8">
                                                <DollarSign size={20} className="text-[#B89C4A]" /> Financial Scope
                                            </h3>
                                            <div className="flex flex-col gap-8 p-8 border border-[#B89C4A]/20 bg-[#0A0A0F]">
                                                <div className="relative z-10">
                                                    <span className="block text-[10px] text-[#6E6E6E] tracking-widest uppercase mb-2">Average Tuition</span>
                                                    <span className="text-xl font-light text-[#F1F1F1] font-[family-name:var(--font-heading)] tracking-wide">{country.tuition}</span>
                                                </div>
                                                <div className="w-full h-px bg-[#B89C4A]/10 relative z-10"></div>
                                                <div className="relative z-10">
                                                    <span className="block text-[10px] text-[#6E6E6E] tracking-widest uppercase mb-2">Estimated Living Cost</span>
