"use client";

import { useRef, useMemo } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import * as THREE from "three";

function Particles({ count = 8000 }) {
    const mesh = useRef<THREE.InstancedMesh>(null);
    const dummy = useMemo(() => new THREE.Object3D(), []);

    interface ParticleType {
        t: number;
        factor: number;
        speed: number;
        xFactor: number;
        yFactor: number;
        zFactor: number;
        mx: number;
        my: number;
    }

    // Generate random positions
    const particles = useMemo(() => {
        const temp: ParticleType[] = [];
        for (let i = 0; i < count; i++) {
            const t = Math.random() * 100;
            const factor = 10 + Math.random() * 20;
            const speed = 0.01 + Math.random() / 200;
            const xFactor = -50 + Math.random() * 100;
            const yFactor = -50 + Math.random() * 100;
            const zFactor = -50 + Math.random() * 100;
            temp.push({ t, factor, speed, xFactor, yFactor, zFactor, mx: 0, my: 0 });
        }
        return temp;
    }, [count]);

    useFrame((state) => {
        if (!mesh.current) return;
        particles.forEach((particle, i) => {
            let { t } = particle;
            const { factor, speed, xFactor, yFactor, zFactor } = particle;
            t = particle.t += speed / 2;
            const a = Math.cos(t) + Math.sin(t * 1) / 10;
            const b = Math.sin(t) + Math.cos(t * 2) / 10;
            const s = Math.cos(t);

            // Math to make them swirl in a big clump
            dummy.position.set(
                (particle.mx / 10) * a + xFactor + Math.cos((t / 10) * factor) + (Math.sin(t * 1) * factor) / 10,
                (particle.my / 10) * b + yFactor + Math.sin((t / 10) * factor) + (Math.cos(t * 2) * factor) / 10,
                (particle.my / 10) * b + zFactor + Math.cos((t / 10) * factor) + (Math.sin(t * 3) * factor) / 10
            );

            // Interactive parallax using mouse pointer natively
            const mouseX = state.pointer.x * 20;
            const mouseY = state.pointer.y * 20;

            // Update position with slight mouse influence, but smooth
            dummy.position.x += (mouseX - dummy.position.x) * 0.05;
            dummy.position.y += (mouseY - dummy.position.y) * 0.05;

            dummy.scale.set(s * 0.5, s * 0.5, s * 0.5);
            dummy.rotation.set(s * 5, s * 5, s * 5);
            dummy.updateMatrix();
            mesh.current!.setMatrixAt(i, dummy.matrix);
        });
        mesh.current.instanceMatrix.needsUpdate = true;
    });

    return (
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        <instancedMesh ref={mesh} args={[null as any, null as any, count]} position={[0, 0, -20]}>
            <circleGeometry args={[0.1, 8]} />
            <meshBasicMaterial color="#ffffff" transparent opacity={0.6} blending={THREE.AdditiveBlending} depthWrite={false} />
        </instancedMesh>
    );
}

export default function ParticleBackground() {
    return (
        <div className="absolute inset-0 z-0 bg-[#0A0A0F] pointer-events-none">
            <Canvas camera={{ fov: 60, position: [0, 0, 40] }}>
                <Particles count={4000} />
            </Canvas>
            <div className="absolute inset-0 bg-gradient-to-b from-transparent to-[#0A0A0F] z-10 pointers-events-none" />
        </div>
    );
}
